public class Doubler {
    public static void doubleAll(int[] arr) {
        for (int n : arr) {
            n *= 2;   // modifies local copy, not the array element
        }
    }
    public static void main(String[] args) {
        int[] a = {1, 2, 3};
        doubleAll(a);
        System.out.println(a[0]);  // prints 1, not 2
    }
}
